{
    std::array<std::array<int, 3>, 2> g = {{
        {1, 2, 3},
        {4, 5, 6}
    }};
    for (std::size_t r = 0; r < g.size(); ++r)
        for (std::size_t c = 0; c < g.size(); ++c)  // BUG
            std::cout << g[r][c] << ' ';
    std::cout << '\n';
    return 0;
}
